// ═══════════════════════════════════════════════════
// ISOMETRIC BOARD (Canvas — Prisma Quest engine)
// ═══════════════════════════════════════════════════

function IsometricBoard({ teams, currentTeamIdx, board, gridSize, hasImage }) {
  const canvasRef = useRef(null);
  const teamsRef  = useRef(teams);
  const curRef    = useRef(currentTeamIdx);
  useEffect(() => { teamsRef.current = teams; },         [teams]);
  useEffect(() => { curRef.current = currentTeamIdx; },  [currentTeamIdx]);

  useEffect(() => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    // ── Hi-DPI / HD resolution fix ────────────────
    const DPR = window.devicePixelRatio || 1;
    const W_CSS = canvas.parentElement?.clientWidth  || 900;
    const H_CSS = canvas.parentElement?.clientHeight || 900;
    // Physical pixels — crisp on retina/4K/HD screens
    canvas.width  = W_CSS * DPR;
    canvas.height = H_CSS * DPR;
    canvas.style.width  = W_CSS + "px";
    canvas.style.height = H_CSS + "px";
    const W = canvas.width;
    const H = canvas.height;
    const ctx = canvas.getContext("2d");
    ctx.scale(DPR, DPR); // all drawing coords stay in CSS pixels
    // Re-alias W/H to CSS pixels for all drawing logic
    const CW = W_CSS, CH = H_CSS;

    const GRID    = gridSize || 9;
    const boardData = board || generateBoard(GRID * GRID);
    // Larger base tile — fills a big screen better
    const TW_base = 52;
    const TH_base = 26;
    const SH_base = 13;
    const ZRISE   = 0.45;
    const SPACING = 1.55;

    // spiral of GRID×GRID then slice to boardData length
    function spiralPath(n) {
      const p = []; let r1=0,r2=n-1,c1=0,c2=n-1;
      while(r1<=r2&&c1<=c2){
        for(let c=c1;c<=c2;c++)p.push([r1,c]); r1++;
        for(let r=r1;r<=r2;r++)p.push([r,c2]); c2--;
        if(r1<=r2){for(let c=c2;c>=c1;c--)p.push([r2,c]);r2--;}
        if(c1<=c2){for(let r=r2;r>=r1;r--)p.push([r,c1]);c1++;}
      }
      return p;
    }
    const PATH = spiralPath(GRID).slice(0, boardData.length);
    const N = PATH.length;

    // Flip so step 0 (START) is front-bottom
    const steps = PATH.map(([origRow, origCol], idx) => {
      const row = (GRID-1) - origRow;
      const col = (GRID-1) - origCol;
      const z   = idx * ZRISE;
      const sx  = (col - row) * TW_base * SPACING;
      const sy  = (col + row) * TH_base * SPACING - z;
      const cell = boardData[idx] || { type:"trivia" };
      const hue  = CT[cell.type]?.hue ?? 200;
      return { row, col, idx, hue, z, sx, sy, cell };
    });

    // Auto-fit — use CSS dimensions for layout
    const TITLE_H = 10, PAD = 32;
    const allX = steps.flatMap(s=>[s.sx-TW_base, s.sx+TW_base]);
    const allY = steps.flatMap(s=>[s.sy-TH_base-30, s.sy+TH_base+SH_base+4]);
    const minX=Math.min(...allX), maxX=Math.max(...allX);
    const minY=Math.min(...allY), maxY=Math.max(...allY);
    const availW = CW - PAD*2;
    const availH = CH - TITLE_H - PAD*2;
    const scale  = Math.min(availW/(maxX-minX), availH/(maxY-minY));
    const OX = PAD + (availW-(maxX-minX)*scale)/2 - minX*scale;
    const OY = TITLE_H + PAD + (availH-(maxY-minY)*scale)/2 - minY*scale;

    steps.forEach(s => {
      s.sx = s.sx*scale + OX;
      s.sy = s.sy*scale + OY;
    });
    const tw = TW_base*scale, th = TH_base*scale, sh = SH_base*scale;

    // Painter sort
    const drawOrder = [...steps].sort((a,b) => {
      const da = a.row+a.col, db = b.row+b.col;
      if(da!==db) return da-db;
      return a.idx-b.idx;
    });

    // ── Helpers ───────────────────────────────────
    const hsl = (h,s,l,a=1) => `hsla(${h},${s}%,${l}%,${a})`;

    function drawTile(s, glow, shimmer) {
      const {sx,sy,hue,idx,cell} = s;
      const h = hue;
      const isStart  = idx === 0;
      const isMeta   = idx === N-1;
      const glowMult = glow ? 1.15 : 1;

      // Right face
      ctx.beginPath();
      ctx.moveTo(sx+tw,sy); ctx.lineTo(sx,sy+th);
      ctx.lineTo(sx,sy+th+sh); ctx.lineTo(sx+tw,sy+sh);
      ctx.closePath();
      ctx.fillStyle = glow ? hsl(h,90,36) : hsl(h,80,25);
      ctx.fill();
      ctx.strokeStyle = hsl(h,60,10,.7); ctx.lineWidth=.6; ctx.stroke();

      // Left face
      ctx.beginPath();
      ctx.moveTo(sx-tw,sy); ctx.lineTo(sx,sy+th);
      ctx.lineTo(sx,sy+th+sh); ctx.lineTo(sx-tw,sy+sh);
      ctx.closePath();
      ctx.fillStyle = glow ? hsl(h,85,26) : hsl(h,75,17);
      ctx.fill();
      ctx.strokeStyle = hsl(h,60,8,.7); ctx.lineWidth=.6; ctx.stroke();

      // Top face
      ctx.beginPath();
      ctx.moveTo(sx,sy-th); ctx.lineTo(sx+tw,sy);
      ctx.lineTo(sx,sy+th); ctx.lineTo(sx-tw,sy);
      ctx.closePath();
      const g = ctx.createLinearGradient(sx-tw,sy-th,sx+tw,sy+th);
      if(glow) {
        g.addColorStop(0, hsl(h,100,92)); g.addColorStop(.5,hsl(h,100,74)); g.addColorStop(1,hsl(h,95,58));
      } else {
        g.addColorStop(0, hsl(h,95,72)); g.addColorStop(.5,hsl(h,100,60)); g.addColorStop(1,hsl(h,90,48));
      }
      ctx.fillStyle=g; ctx.fill();
      ctx.strokeStyle=hsl(h,60,22,.4); ctx.lineWidth=.6; ctx.stroke();

      // Sheen
      ctx.save();
      ctx.beginPath();
      ctx.moveTo(sx,sy-th); ctx.lineTo(sx+tw,sy);
      ctx.lineTo(sx,sy+th); ctx.lineTo(sx-tw,sy);
      ctx.closePath(); ctx.clip();
      ctx.beginPath();
      ctx.moveTo(sx-tw*.45, sy-th*.75);
      ctx.lineTo(sx+tw*.08, sy-th*.08);
      ctx.strokeStyle="rgba(255,255,255,.16)"; ctx.lineWidth=tw*.16; ctx.stroke();
      ctx.restore();

      // Icon + number
      const iconFontSize = Math.max(7, Math.round(tw*.35));
      const numFontSize  = Math.max(6, Math.round(tw*.28));
      ctx.save();
      ctx.textAlign="center"; ctx.textBaseline="middle";
      // icon
      ctx.font = `${iconFontSize}px serif`;
      ctx.fillText(CT[cell.type]?.icon ?? "❓", sx, sy - th*0.18);
      // step number
      ctx.font = `bold ${numFontSize}px Georgia,serif`;
      ctx.fillStyle="rgba(0,0,0,.55)";
      ctx.fillText(idx+1, sx+.5, sy+th*.45+.8);
      ctx.fillStyle="rgba(255,255,255,.92)";
      ctx.fillText(idx+1, sx, sy+th*.45);
      ctx.restore();
    }

    function drawStartBadge(s) {
      const {sx,sy} = s;
      const bx=sx, by=sy-th-16;
      ctx.save();
      ctx.shadowColor="rgba(74,222,128,.8)"; ctx.shadowBlur=16;
      ctx.beginPath(); ctx.roundRect(bx-30,by-9,60,18,9);
      ctx.fillStyle="rgba(22,163,74,.92)"; ctx.fill();
      ctx.restore();
      ctx.save();
      ctx.textAlign="center"; ctx.textBaseline="middle";
      ctx.font="bold 10px Georgia,serif";
      ctx.fillStyle="rgba(255,255,255,.98)";
      ctx.fillText("▶ START", bx, by);
      ctx.restore();
      ctx.beginPath(); ctx.moveTo(bx,by+10); ctx.lineTo(bx,sy-th-2);
      ctx.strokeStyle="rgba(74,222,128,.6)"; ctx.lineWidth=1.5;
      ctx.setLineDash([3,3]); ctx.stroke(); ctx.setLineDash([]);
    }

    function drawDiamond(s, frame) {
      const {sx,sy} = s;
      const pulse = .5+.5*Math.sin(frame*.045);
      const dcx=sx, dcy=sy-th-2;
      const r=(tw*.5)+pulse*(tw*.09);

      const aura=ctx.createRadialGradient(dcx,dcy,0,dcx,dcy,r*3.2);
      aura.addColorStop(0,`rgba(255,255,200,${.6+pulse*.22})`);
      aura.addColorStop(.25,"rgba(255,220,80,.2)");
      aura.addColorStop(.6,"rgba(200,160,50,.06)");
      aura.addColorStop(1,"rgba(0,0,0,0)");
      ctx.beginPath(); ctx.arc(dcx,dcy,r*3.2,0,Math.PI*2);
      ctx.fillStyle=aura; ctx.fill();

      const F=[
        {pts:[[0,-1],[.55,-.3],[0,0]],l:240},
        {pts:[[0,-1],[-.55,-.3],[0,0]],l:195},
        {pts:[[.55,-.3],[1,.2],[0,.85],[0,0]],l:165},
        {pts:[[-.55,-.3],[-1,.2],[0,.85],[0,0]],l:135},
        {pts:[[1,.2],[0,.85],[0,0]],l:150},
        {pts:[[-.1,.2],[0,.85],[0,0]],l:115},
      ];
      F.forEach(({pts,l})=>{
        ctx.beginPath();
        pts.forEach(([px,py],i)=>{
          i===0?ctx.moveTo(dcx+px*r,dcy+py*r):ctx.lineTo(dcx+px*r,dcy+py*r);
        });
        ctx.closePath();
        const v=Math.min(255,l);
        ctx.fillStyle=`rgba(${v},${Math.min(255,v+40)},120,.94)`;
        ctx.fill();
        ctx.strokeStyle="rgba(255,255,200,.3)"; ctx.lineWidth=.5; ctx.stroke();
      });
      const sp=ctx.createRadialGradient(dcx,dcy-r*.35,0,dcx,dcy,r*.55);
      sp.addColorStop(0,"rgba(255,255,200,1)"); sp.addColorStop(1,"rgba(255,255,200,0)");
      ctx.beginPath(); ctx.arc(dcx,dcy-r*.3,r*.3,0,Math.PI*2);
      ctx.fillStyle=sp; ctx.fill();
      ctx.save();
      ctx.shadowColor="rgba(255,230,80,.9)"; ctx.shadowBlur=10;
      ctx.textAlign="center";
      ctx.font="bold 10px Georgia,serif";
      ctx.fillStyle="rgba(255,255,200,.97)";
      ctx.fillText("✦ GOAL", dcx, dcy-r-8);
      ctx.restore();
    }

    function drawTeamTokens(frame) {
      const curTeams = teamsRef.current;
      const activeIdx = curRef.current;

      // Group teams by position
      const byPos = {};
      curTeams.forEach((t,ti) => {
        const pos = t.position ?? 0;
        if (!byPos[pos]) byPos[pos] = [];
        byPos[pos].push({ t, ti });
      });

      Object.entries(byPos).forEach(([pos, group]) => {
        const s = steps[parseInt(pos)];
        if (!s) return;
        group.forEach(({ t, ti }, gi) => {
          const isActive = ti === activeIdx;
          const bounce = isActive ? Math.sin(frame * .08) * 2.5 : 0;
          const ox = (gi - (group.length-1)/2) * (tw*0.38);
          const cx = s.sx + ox;
          const cy = s.sy - th - 10 + bounce;
          const r  = Math.max(6, tw * 0.28);

          // Glow for active
          if (isActive) {
            ctx.save();
            ctx.shadowColor = TEAM_COLORS[t.colorIdx].bg;
            ctx.shadowBlur  = 12;
          }
          // Circle
          ctx.beginPath();
          ctx.arc(cx, cy, r, 0, Math.PI*2);
          ctx.fillStyle = TEAM_COLORS[t.colorIdx].bg;
          ctx.fill();
          ctx.strokeStyle = isActive ? "#fff" : "rgba(255,255,255,.6)";
          ctx.lineWidth = isActive ? 2 : 1.2;
          ctx.stroke();
          if (isActive) ctx.restore();

          // Letter
          ctx.save();
          ctx.textAlign = "center";
          ctx.textBaseline = "middle";
          ctx.font = `bold ${Math.max(7, Math.round(r*0.95))}px Cinzel,serif`;
          ctx.fillStyle = "#fff";
          ctx.fillText(String.fromCharCode(65+t.id), cx, cy+0.5);
          ctx.restore();
        });
      });
    }

    // ── Stars background ──────────────────────────
    const stars = Array.from({length:220}, () => ({
      x:Math.random()*CW, y:Math.random()*CH,
      r:Math.random()*1.6+0.3,
      a:Math.random()*.4+.06,
    }));

    // ── Legend ────────────────────────────────────
    function drawLegend() {
      const types = ["trivia","identify","foodchain","hangman","match","unscramble","wildcard"];
      const cols = 4, itemW = CW/cols, itemH = 20;
      const startX = 8, startY = CH - itemH*(Math.ceil(types.length/cols)) - 6;
      types.forEach((type, i) => {
        const col = i % cols, row = Math.floor(i / cols);
        const x = startX + col*itemW, y = startY + row*itemH;
        const c = CT[type];
        ctx.beginPath();
        ctx.arc(x+9, y+8, 7, 0, Math.PI*2);
        ctx.fillStyle = c.color; ctx.fill();
        ctx.save();
        ctx.font = "13px Georgia,serif";
        ctx.fillStyle = "rgba(210,210,210,.85)";
        ctx.textBaseline = "middle";
        ctx.fillText(`${c.icon} ${c.label}`, x+20, y+8.5);
        ctx.restore();
      });
    }

    // ── Render loop ───────────────────────────────
    let animId, frame=0, shimIdx=0, shimTimer=0;

    function render() {
      frame++;
      shimTimer++;
      if(shimTimer>=6){ shimTimer=0; shimIdx=(shimIdx+1)%N; }

      // Canvas is transparent — background ecosystem shows through gaps between tiles
      ctx.clearRect(0,0,CW,CH);

      // Stars — only when no background image
      if (!hasImage) {
        stars.forEach(s => {
          ctx.beginPath(); ctx.arc(s.x,s.y,s.r,0,Math.PI*2);
          ctx.fillStyle=`rgba(160,185,255,${s.a})`; ctx.fill();
        });
      }

      // Tiles (back to front, skip META)
      for(const s of drawOrder){
        if(s.idx===N-1) continue;
        drawTile(s, s.idx===shimIdx);
      }
      // META on top
      drawTile(steps[N-1], true);
      drawDiamond(steps[N-1], frame);

      // START badge
      drawStartBadge(steps[0]);

      // Team tokens (above tiles)
      drawTeamTokens(frame);

      // Legend
      drawLegend();

      animId = requestAnimationFrame(render);
    }
    render();
    return () => cancelAnimationFrame(animId);
  }, []); // mount once; team data via refs

  return (
    <canvas ref={canvasRef} style={{width:"100%",height:"100%",display:"block",background:"transparent"}} />
  );
}

const GS = `
  @import url('https://fonts.googleapis.com/css2?family=Cinzel+Decorative:wght@700&family=Cinzel:wght@400;600;700&family=Libre+Baskerville:ital,wght@0,400;0,700;1,400&display=swap');
  * { box-sizing: border-box; margin: 0; padding: 0; }
  html { font-size: clamp(14px, 1.4vw, 22px); }
  body { overflow-x: hidden; }
  @keyframes float { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-10px)} }
  @keyframes fadeUp { from{opacity:0;transform:translateY(20px)} to{opacity:1;transform:translateY(0)} }
  @keyframes popIn { 0%{opacity:0;transform:scale(0.4)} 70%{transform:scale(1.1)} 100%{opacity:1;transform:scale(1)} }
  @keyframes twinkle { 0%,100%{opacity:0.15;transform:scale(0.8)} 50%{opacity:0.8;transform:scale(1.2)} }
  @keyframes diceRoll { 0%{transform:scale(1) rotate(0deg)} 50%{transform:scale(1.2) rotate(180deg)} 100%{transform:scale(1) rotate(360deg)} }
  @keyframes chaosFloat { 0%{transform:translate(0,0) rotate(0deg);opacity:0.05} 25%{transform:translate(-8px,6px) rotate(45deg);opacity:0.12} 50%{transform:translate(5px,-4px) rotate(90deg);opacity:0.06} 75%{transform:translate(-3px,8px) rotate(135deg);opacity:0.10} 100%{transform:translate(0,0) rotate(180deg);opacity:0.05} }
  @keyframes genesisReveal { from{opacity:0;letter-spacing:0.6em} to{opacity:1;letter-spacing:0.12em} }
  @keyframes lightBurst { 0%{opacity:0;transform:scale(0.3)} 60%{opacity:1;transform:scale(1.2)} 100%{opacity:1;transform:scale(1)} }
  @keyframes narrativeSlide { from{opacity:0;transform:translateY(-12px)} to{opacity:1;transform:translateY(0)} }
  ::-webkit-scrollbar{width:7px} ::-webkit-scrollbar-track{background:rgba(255,255,255,0.04)} ::-webkit-scrollbar-thumb{background:rgba(255,255,255,0.18);border-radius:4px}
`;

const shuffle = arr => [...arr].sort(() => Math.random() - 0.5);
const pick = arr => arr[Math.floor(Math.random() * arr.length)];

// ── ECOSYSTEM BACKGROUND IMAGES ────────────────────
// ── ECOSYSTEM BACKGROUND IMAGES (base64 embedded) ──
const ECO_IMAGES = {
  desert:    "data:image/jpeg;base64,",
  tropical:  "data:image/jpeg;base64,",
  savanna:   "data:image/jpeg;base64,",
  ocean:     "data:image/jpeg;base64,",
  tundra:    "data:image/jpeg;base64,",
  wetland:   "data:image/jpeg;base64,",
  coralreef: "data:image/jpeg;base64,",
};


const GENESIS_Q = {
  q: "What was the first thing God created?",
  opts: ["💧 Water", "☀️ Light", "🌍 Dry land", "🌿 Plants"],
  a: 1, // La luz — Génesis 1:3
  ref: "Genesis 1:3 — \"And God said, Let there be light: and there was light.\""
};

function GenesisScreen({ teams, onStart }) {
  const [phase, setPhase] = useState(0); // 0=chaos 1=text 2=light 3=question
  // Spinner state
  const [activeTeams, setActiveTeams] = useState(teams);
  const [spinning, setSpinning] = useState(false);
  const [deg, setDeg] = useState(0);
  const [chosen, setChosen] = useState(null);   // team object
  const [spinPhase, setSpinPhase] = useState("spin"); // spin | question | wrong
  const [sel, setSel] = useState(null);
  const spinDegRef = useRef(0);

  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 800);
    const t2 = setTimeout(() => setPhase(2), 3200);
    const t3 = setTimeout(() => setPhase(3), 5000);
    return () => { clearTimeout(t1); clearTimeout(t2); clearTimeout(t3); };
  }, []);

  const doSpin = () => {
    if (spinning || spinPhase !== "spin") return;
    setSpinning(true); setChosen(null);
    const n = activeTeams.length;
    const winIdx = Math.floor(Math.random() * n);
    const sd = 360 / n;
    const totalRot = spinDegRef.current + 1800 + (360 - (winIdx * sd + sd / 2)) - (spinDegRef.current % 360);
    spinDegRef.current = totalRot;
    setDeg(totalRot);
    setTimeout(() => {
      setSpinning(false);
      setChosen(activeTeams[winIdx]);
      setSpinPhase("question");
    }, 4200);
  };

  const answer = (idx) => {
    if (sel !== null) return;
    setSel(idx);
    if (idx === GENESIS_Q.a) {
      // Correct — find this team's original index and start game
      setTimeout(() => {
        const origIdx = teams.findIndex(t => t.id === chosen.id);
        onStart(origIdx >= 0 ? origIdx : 0);
      }, 1600);
    } else {
      // Wrong — remove from wheel and spin again
      setTimeout(() => {
        const remaining = activeTeams.filter(t => t.id !== chosen.id);
        const next = remaining.length > 0 ? remaining : [...teams]; // reset if all wrong
        setActiveTeams(next);
        setChosen(null); setSel(null); setSpinPhase("spin");
      }, 2000);
    }
  };

  const n = activeTeams.length;
  const conicParts = activeTeams.map((t, i) => `${TEAM_COLORS[t.colorIdx].bg} ${(i/n)*100}% ${((i+1)/n)*100}%`).join(", ");
  const chaosSymbols = ["✦","◆","▲","●","◉","⬟","⬡","⟐","⋆","✧","◈","⬢","⬣"];

  return (
    <div style={{minHeight:"100vh",background:"#000",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"flex-start",fontFamily:"'Libre Baskerville',serif",overflow:"hidden auto",position:"relative",paddingBottom:40}}>
      {/* Chaos particles */}
      {Array.from({length:60}).map((_,i)=>(
        <div key={i} style={{position:"fixed",left:`${(i*17.3)%100}%`,top:`${(i*13.7)%100}%`,fontSize:Math.random()*18+8,color:"rgba(100,100,150,1)",animation:`chaosFloat ${3+Math.random()*5}s ease-in-out ${Math.random()*4}s infinite`,pointerEvents:"none",opacity:phase<2?1:0,transition:"opacity 2s ease"}}>
          {chaosSymbols[i%chaosSymbols.length]}
        </div>
      ))}
      {/* Light burst */}
      {phase>=2&&(
        <div style={{position:"fixed",inset:0,background:"radial-gradient(ellipse at 50% 40%, rgba(255,245,200,0.18) 0%, rgba(255,220,100,0.06) 40%, transparent 70%)",animation:"lightBurst 2s ease forwards",pointerEvents:"none"}} />
      )}

      {/* ── GENESIS TEXT ── */}
      <div style={{textAlign:"center",zIndex:10,padding:"60px 32px 0",maxWidth:700,width:"100%"}}>
        {phase>=1&&(
          <div style={{animation:"genesisReveal 2s ease forwards"}}>
            <div style={{fontSize:11,letterSpacing:"0.5em",color:"rgba(200,180,120,0.6)",marginBottom:24,textTransform:"uppercase"}}>Genesis 1:1</div>
            <p style={{fontSize:22,color:"rgba(255,245,210,0.92)",lineHeight:1.8,fontStyle:"italic",textShadow:"0 0 40px rgba(255,220,100,0.3)",marginBottom:8}}>
              "In the beginning God created<br/>the heavens and the earth."
            </p>
            <p style={{fontSize:14,color:"rgba(180,160,100,0.7)",lineHeight:1.7,marginTop:16}}>
              The earth was formless and empty,<br/>darkness was over the surface of the deep.
            </p>
          </div>
        )}
        {phase>=2&&(
          <div style={{marginTop:28,animation:"fadeUp 1.5s ease forwards"}}>
            <div style={{fontSize:36,marginBottom:4,animation:"float 3s ease-in-out infinite"}}>✨</div>
            <p style={{fontSize:13,color:"rgba(255,245,200,0.5)",letterSpacing:"0.3em",textTransform:"uppercase"}}>
              And God said — "Let there be light"
            </p>
          </div>
        )}
      </div>

      {/* ── QUESTION + SPINNER (phase 3) ── */}
      {phase>=3&&(
        <div style={{zIndex:10,width:"100%",maxWidth:560,padding:"0 20px",marginTop:36,animation:"fadeUp 0.8s ease"}}>
          {/* Divider */}
          <div style={{height:1,background:"linear-gradient(90deg,transparent,rgba(200,160,60,0.4),transparent)",marginBottom:32}} />

          {/* Question */}
          <div style={{textAlign:"center",marginBottom:28}}>
            <div style={{fontSize:11,letterSpacing:"0.4em",color:"rgba(200,180,120,0.5)",marginBottom:10,textTransform:"uppercase"}}>Opening Question</div>
            <p style={{fontFamily:"'Cinzel',serif",fontSize:19,color:"rgba(255,245,200,0.95)",lineHeight:1.5,fontWeight:700,margin:0}}>
              {GENESIS_Q.q}
            </p>
          </div>

          {/* Spinner */}
          {spinPhase==="spin"&&(
            <div style={{display:"flex",flexDirection:"column",alignItems:"center",gap:16,marginBottom:24}}>
              <div style={{fontSize:12,color:"rgba(255,255,255,0.35)",letterSpacing:"0.2em"}}>
                {activeTeams.length < teams.length ? `Remaining teams: ${activeTeams.map(t=>t.name).join(", ")}` : "Spin the wheel to decide who answers"}
              </div>
              <div style={{position:"relative"}}>
                <div style={{position:"absolute",top:-16,left:"50%",transform:"translateX(-50%)",zIndex:10,fontSize:22,color:"rgba(255,220,100,0.9)"}}>▼</div>
                <div style={{width:240,height:240,borderRadius:"50%",background:`conic-gradient(${conicParts})`,transform:`rotate(${deg}deg)`,transition:spinning?"transform 4.2s cubic-bezier(0.17,0.67,0.12,1)":"none",border:"3px solid rgba(255,255,255,0.15)",position:"relative",boxShadow:"0 0 40px rgba(200,160,60,0.15)"}}>
                  {activeTeams.map((t,i)=>{
                    const angle=(i/n+0.5/n)*360-90, rad=angle*Math.PI/180;
                    return(
                      <div key={t.id} style={{position:"absolute",left:120+85*Math.cos(rad),top:120+85*Math.sin(rad),transform:"translate(-50%,-50%)",pointerEvents:"none",textAlign:"center"}}>
                        <div style={{fontFamily:"'Cinzel',serif",fontSize:9,fontWeight:700,color:"#fff",textShadow:"0 1px 4px rgba(0,0,0,0.9)",whiteSpace:"nowrap",maxWidth:60,overflow:"hidden",textOverflow:"ellipsis"}}>{t.name}</div>
                      </div>
                    );
                  })}
                </div>
                <div style={{position:"absolute",top:"50%",left:"50%",transform:"translate(-50%,-50%)",width:44,height:44,borderRadius:"50%",background:"#050508",border:"2px solid rgba(255,255,255,0.2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:18,zIndex:5}}>📖</div>
              </div>
              <button onClick={doSpin} disabled={spinning} style={{padding:"13px 40px",background:spinning?"rgba(255,255,255,0.04)":"linear-gradient(135deg,rgba(200,160,60,0.3),rgba(255,220,100,0.2))",border:"1px solid rgba(200,160,60,0.4)",borderRadius:12,color:spinning?"rgba(255,255,255,0.3)":"rgba(255,245,200,0.9)",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:13,cursor:spinning?"not-allowed":"pointer",letterSpacing:"0.15em",boxShadow:spinning?"none":"0 0 20px rgba(200,160,60,0.2)"}}>
                {spinning?"Spinning…":"⚡ SPIN"}
              </button>
            </div>
          )}

          {/* Answer phase */}
          {spinPhase==="question"&&chosen&&(
            <div style={{animation:"fadeUp 0.5s ease"}}>
              <div style={{textAlign:"center",marginBottom:16}}>
                <div style={{display:"inline-flex",alignItems:"center",gap:10,background:`rgba(0,0,0,0.4)`,border:`1px solid ${TEAM_COLORS[chosen.colorIdx].bg}44`,borderRadius:12,padding:"10px 20px"}}>
                  <div style={{width:10,height:10,borderRadius:"50%",background:TEAM_COLORS[chosen.colorIdx].bg,boxShadow:`0 0 8px ${TEAM_COLORS[chosen.colorIdx].bg}`}} />
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:14,color:TEAM_COLORS[chosen.colorIdx].light,fontWeight:700}}>{chosen.name}</span>
                  <span style={{fontSize:12,color:"rgba(255,255,255,0.4)"}}>answers</span>
                </div>
              </div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:14}}>
                {GENESIS_Q.opts.map((opt,i)=>{
                  let bg="rgba(255,255,255,0.07)",border="1px solid rgba(255,255,255,0.12)",color="rgba(255,255,255,0.85)";
                  if(sel!==null){
                    if(i===GENESIS_Q.a){bg="rgba(22,163,74,0.25)";border="1.5px solid #22c55e";color="#4ade80";}
                    else if(i===sel){bg="rgba(239,68,68,0.2)";border="1.5px solid #ef4444";color="#f87171";}
                  }
                  return(
                    <button key={i} onClick={()=>answer(i)} style={{background:bg,border,borderRadius:12,padding:"14px 16px",color,fontFamily:"'Libre Baskerville',serif",fontSize:14,cursor:sel!==null?"default":"pointer",transition:"all 0.2s",textAlign:"center"}}>
                      {opt}
                    </button>
                  );
                })}
              </div>
              {sel===GENESIS_Q.a&&(
                <div style={{textAlign:"center",animation:"popIn 0.4s ease"}}>
                  <div style={{fontSize:13,color:"#4ade80",fontStyle:"italic",marginBottom:4}}>✓ Correct!</div>
                  <div style={{fontSize:11,color:"rgba(200,180,120,0.6)"}}>{GENESIS_Q.ref}</div>
                  <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",marginTop:6,letterSpacing:"0.2em"}}>STARTING EXPLORATION…</div>
                </div>
              )}
              {sel!==null&&sel!==GENESIS_Q.a&&(
                <div style={{textAlign:"center",animation:"popIn 0.4s ease"}}>
                  <div style={{fontSize:13,color:"#f87171",marginBottom:4}}>✗ Incorrect — {chosen.name} loses their turn</div>
                  <div style={{fontSize:11,color:"rgba(200,180,120,0.5)"}}>{GENESIS_Q.ref}</div>
                  <div style={{fontSize:11,color:"rgba(255,255,255,0.3)",marginTop:6,letterSpacing:"0.2em"}}>GIRANDO DE NUEVO…</div>
                </div>
              )}
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ── SETUP SCREEN ────────────────────────────────────
function SetupScreen({ onStart }) {
  const [step, setStep] = useState(0);
  const [eco, setEco] = useState(null);
  const [numTeams, setNumTeams] = useState(2);
  const [teams, setTeams] = useState([]);
  const [editing, setEditing] = useState({ idx:0, name:"Team 1", players:[""] });
  const ecoList = Object.values(ECOSYSTEMS).sort((a,b)=>a.difficulty-b.difficulty);
  const diffColors = {1:"#4ade80",2:"#86efac",3:"#fbbf24",4:"#f97316",5:"#f87171"};

  const initTeams = n => {
    const t = Array.from({length:n},(_,i)=>({id:i,name:`Team ${i+1}`,players:[""],colorIdx:i}));
    setTeams(t); setEditing({idx:0,name:t[0].name,players:[""]}); setNumTeams(n);
  };
  const saveEditing = () => {
    const cleaned = editing.players.filter(p=>p.trim());
    setTeams(prev=>prev.map((t,i)=>i===editing.idx?{...t,name:editing.name||t.name,players:cleaned.length?cleaned:t.players}:t));
  };
  const canProceed = step===0?eco:step===1?numTeams>=2:teams.every(t=>t.players.filter(p=>p.trim()).length>0);

  const particles = useMemo(() => Array.from({length:40}, () => ({
    left: Math.random()*100, top: Math.random()*100, delay: Math.random()*4, dur: 2+Math.random()*3
  })), []);

  return (
    <div style={{minHeight:"100vh",background:"radial-gradient(ellipse at 30% 20%,#0d1a0e,#020407 60%)",fontFamily:"'Libre Baskerville',serif",display:"flex",flexDirection:"column",alignItems:"center",padding:"40px 20px",position:"relative",overflow:"hidden"}}>
      {particles.map((p,i)=>(
        <div key={i} style={{position:"absolute",left:`${p.left}%`,top:`${p.top}%`,width:2,height:2,borderRadius:"50%",background:"#fff",animation:`twinkle ${p.dur}s ease-in-out ${p.delay}s infinite`,opacity:0.3,pointerEvents:"none"}} />
      ))}
      <div style={{textAlign:"center",marginBottom:36,animation:"fadeUp 0.7s ease"}}>
        <div style={{fontSize:56,marginBottom:8,animation:"float 3s ease-in-out infinite",filter:"drop-shadow(0 0 20px rgba(34,197,94,0.5))"}}>🌍</div>
        <h1 style={{fontFamily:"'Cinzel Decorative',serif",fontSize:24,color:"#fff",letterSpacing:"0.08em",textShadow:"0 0 30px rgba(74,222,128,0.4)"}}>ECOSYSTEM EXPLORER</h1>
        <div style={{fontSize:11,color:"#4ade80",letterSpacing:"0.3em",marginTop:4}}>BOARD GAME · 36–72 SQUARES · 7TH GRADE</div>
      </div>
      <div style={{display:"flex",gap:8,marginBottom:32}}>
        {["Ecosystem","Teams","Players"].map((s,i)=>(
          <div key={i} style={{display:"flex",alignItems:"center",gap:8}}>
            <div style={{width:28,height:28,borderRadius:"50%",background:i<=step?"#22c55e":"rgba(255,255,255,0.08)",border:`2px solid ${i<=step?"#22c55e":"rgba(255,255,255,0.15)"}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:12,fontWeight:700,color:i<=step?"#fff":"rgba(255,255,255,0.3)",fontFamily:"'Cinzel',serif"}}>{i+1}</div>
            <span style={{fontSize:11,color:i<=step?"#86efac":"rgba(255,255,255,0.3)",letterSpacing:"0.1em"}}>{s}</span>
            {i<2&&<div style={{width:24,height:1,background:"rgba(255,255,255,0.1)"}} />}
          </div>
        ))}
      </div>
      {step===0&&(
        <div style={{width:"100%",maxWidth:900,animation:"fadeUp 0.5s ease"}}>
          <p style={{textAlign:"center",color:"rgba(255,255,255,0.5)",marginBottom:24,fontSize:13}}>Choose the ecosystem your class will explore</p>
          <div style={{display:"grid",gridTemplateColumns:"repeat(auto-fit,minmax(260px,1fr))",gap:14}}>
            {ecoList.map(e=>(
              <div key={e.id} onClick={()=>setEco(e)} style={{background:eco?.id===e.id?`${e.color}22`:"rgba(255,255,255,0.03)",border:`2px solid ${eco?.id===e.id?e.color:"rgba(255,255,255,0.08)"}`,borderRadius:16,padding:"18px 20px",cursor:"pointer",transition:"all 0.25s",boxShadow:eco?.id===e.id?`0 0 20px ${e.color}44`:"none"}}>
                <div style={{display:"flex",alignItems:"center",gap:12,marginBottom:10}}>
                  <span style={{fontSize:32}}>{e.emoji}</span>
                  <div>
                    <div style={{fontFamily:"'Cinzel',serif",fontSize:14,color:"#fff",fontWeight:700}}>{e.name}</div>
                    <span style={{fontSize:10,background:`${diffColors[e.difficulty]||"#a5f3fc"}22`,color:diffColors[e.difficulty]||"#a5f3fc",border:`1px solid ${diffColors[e.difficulty]||"#a5f3fc"}44`,borderRadius:10,padding:"2px 8px",fontFamily:"'Cinzel',serif"}}>{e.diffLabel}</span>
                  </div>
                </div>
                <div style={{fontSize:11,color:"rgba(255,255,255,0.4)",lineHeight:1.5}}>{e.organisms.length} organisms · {e.boardSize} squares · {e.difficulty>=6?"Expert chains":e.difficulty>=4?"Complex chains":e.difficulty<=2?"Basic chains":"Moderate chains"}</div>
              </div>
            ))}
          </div>
        </div>
      )}
      {step===1&&(
        <div style={{width:"100%",maxWidth:500,animation:"fadeUp 0.5s ease",textAlign:"center"}}>
          <p style={{color:"rgba(255,255,255,0.5)",marginBottom:32,fontSize:13}}>How many teams are playing?</p>
          <div style={{display:"flex",gap:12,justifyContent:"center",flexWrap:"wrap"}}>
            {[2,3,4,5,6].map(n=>(
              <div key={n} onClick={()=>initTeams(n)} style={{width:80,height:80,borderRadius:16,background:numTeams===n?"rgba(34,197,94,0.2)":"rgba(255,255,255,0.04)",border:`2px solid ${numTeams===n?"#22c55e":"rgba(255,255,255,0.1)"}`,cursor:"pointer",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center"}}>
                <span style={{fontFamily:"'Cinzel',serif",fontSize:28,color:numTeams===n?"#4ade80":"rgba(255,255,255,0.6)",fontWeight:700}}>{n}</span>
                <span style={{fontSize:9,color:"rgba(255,255,255,0.35)",letterSpacing:"0.1em"}}>GRUPOS</span>
              </div>
            ))}
          </div>
          <div style={{marginTop:24,display:"flex",gap:10,flexWrap:"wrap",justifyContent:"center"}}>
            {teams.map((t,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,background:"rgba(255,255,255,0.05)",border:`1px solid ${TEAM_COLORS[i].bg}44`,borderRadius:10,padding:"8px 14px"}}>
                <div style={{width:12,height:12,borderRadius:"50%",background:TEAM_COLORS[i].bg}} />
                <span style={{fontSize:12,color:"rgba(255,255,255,0.7)",fontFamily:"'Cinzel',serif"}}>{t.name}</span>
              </div>
            ))}
          </div>
        </div>
      )}
      {step===2&&(
        <div style={{width:"100%",maxWidth:700,animation:"fadeUp 0.5s ease"}}>
          <p style={{textAlign:"center",color:"rgba(255,255,255,0.5)",marginBottom:20,fontSize:13}}>Enter team name and members (max 7)</p>
          <div style={{display:"grid",gridTemplateColumns:"220px 1fr",gap:16}}>
            <div style={{display:"flex",flexDirection:"column",gap:8}}>
              {teams.map((t,i)=>(
                <div key={i} onClick={()=>{saveEditing();setEditing({idx:i,name:t.name,players:[...t.players,""].slice(0,7)});}}
                  style={{background:editing.idx===i?`${TEAM_COLORS[i].bg}22`:"rgba(255,255,255,0.04)",border:`2px solid ${editing.idx===i?TEAM_COLORS[i].bg:"rgba(255,255,255,0.08)"}`,borderRadius:12,padding:"12px 14px",cursor:"pointer"}}>
                  <div style={{display:"flex",alignItems:"center",gap:10}}>
                    <div style={{width:14,height:14,borderRadius:"50%",background:TEAM_COLORS[i].bg}} />
                    <span style={{fontFamily:"'Cinzel',serif",fontSize:12,color:"#fff"}}>{t.name}</span>
                  </div>
                  <div style={{fontSize:10,color:"rgba(255,255,255,0.35)",marginTop:4}}>{t.players.filter(p=>p.trim()).length} jugadores</div>
                </div>
              ))}
            </div>
            <div style={{background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:16,padding:"20px"}}>
              <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
                <div style={{width:16,height:16,borderRadius:"50%",background:TEAM_COLORS[editing.idx].bg}} />
                <input value={editing.name} onChange={e=>setEditing(p=>({...p,name:e.target.value.toUpperCase()}))}
                  style={{flex:1,background:"rgba(255,255,255,0.08)",border:`1px solid ${TEAM_COLORS[editing.idx].bg}55`,borderRadius:8,padding:"8px 12px",color:"#fff",fontFamily:"'Cinzel',serif",fontSize:13,outline:"none"}} placeholder="Team name..." />
              </div>
              <div style={{fontSize:10,color:"rgba(255,255,255,0.35)",letterSpacing:"0.15em",marginBottom:10}}>PLAYERS (max 7)</div>
              {Array.from({length:7}).map((_,i)=>(
                <input key={i} value={editing.players[i]||""} onChange={e=>{const p=[...(editing.players||[])];p[i]=e.target.value.toUpperCase();setEditing(prev=>({...prev,players:p}));}}
                  style={{width:"100%",background:i<4?"rgba(255,255,255,0.06)":"rgba(255,255,255,0.03)",border:`1px solid rgba(255,255,255,${i<4?0.12:0.06})`,borderRadius:8,padding:"8px 12px",color:"#fff",fontFamily:"'Libre Baskerville',serif",fontSize:13,outline:"none",marginBottom:6}}
                  placeholder={`Jugador ${i+1}${i>=4?" (opcional)":""}`} />
              ))}
              <button onClick={saveEditing} style={{width:"100%",marginTop:8,padding:"10px",background:`${TEAM_COLORS[editing.idx].bg}33`,border:`1px solid ${TEAM_COLORS[editing.idx].bg}55`,borderRadius:10,color:"#fff",fontFamily:"'Cinzel',serif",fontSize:12,cursor:"pointer",letterSpacing:"0.1em"}}>✓ Save Team</button>
            </div>
          </div>
        </div>
      )}
      <div style={{display:"flex",gap:14,marginTop:32}}>
        {step>0&&<button onClick={()=>{saveEditing();setStep(s=>s-1);}} style={{padding:"13px 28px",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:12,color:"rgba(255,255,255,0.7)",fontFamily:"'Cinzel',serif",fontSize:13,cursor:"pointer"}}>← Back</button>}
        <button onClick={()=>{if(!canProceed)return;if(step===2){saveEditing();setTimeout(()=>onStart(eco,teams.map(t=>({...t,players:t.players.filter(p=>p.trim())}))),50);}else{if(step===1&&teams.length===0)initTeams(numTeams);setStep(s=>s+1);}}}
          style={{padding:"13px 36px",background:canProceed?"linear-gradient(135deg,#16a34a,#15803d)":"rgba(255,255,255,0.06)",border:"none",borderRadius:12,color:canProceed?"#fff":"rgba(255,255,255,0.3)",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:13,cursor:canProceed?"pointer":"not-allowed",letterSpacing:"0.1em",boxShadow:canProceed?"0 6px 20px rgba(22,163,74,0.4)":"none"}}>
          {step===2?"🚀 Launch Game!":"Next →"}
        </button>
      </div>
    </div>
  );
}

// ── CHALLENGE COMPONENTS ───────────────────────────
function TriviaChallenge({ data, onResult }) {
  const [sel,setSel]=useState(null);
  const [answered,setAnswered]=useState(false);
  const submit=idx=>{if(answered)return;setSel(idx);setAnswered(true);setTimeout(()=>onResult(idx===data.a),1500);};
  return(
    <div>
      <p style={{fontSize:17,color:"#fff",lineHeight:1.5,fontWeight:"bold",fontFamily:"'Cinzel',serif",marginBottom:20}}>{data.q}</p>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        {data.opts.map((opt,i)=>{
          let bg="rgba(255,255,255,0.07)",border="1px solid rgba(255,255,255,0.12)",color="rgba(255,255,255,0.85)";
          if(answered){if(i===data.a){bg="rgba(22,163,74,0.25)";border="1.5px solid #22c55e";color="#4ade80";}else if(i===sel){bg="rgba(239,68,68,0.2)";border="1.5px solid #ef4444";color="#f87171";}}
          return(<button key={i} onClick={()=>submit(i)} style={{background:bg,border,borderRadius:12,padding:"13px 15px",color,fontFamily:"'Libre Baskerville',serif",fontSize:14,textAlign:"left",cursor:answered?"default":"pointer",transition:"all 0.2s",display:"flex",gap:10,alignItems:"center"}}>
            <span style={{width:24,height:24,borderRadius:"50%",background:"rgba(255,255,255,0.08)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:11,fontFamily:"'Cinzel',serif",flexShrink:0}}>{String.fromCharCode(65+i)}</span>{opt}
          </button>);
        })}
      </div>
      {answered&&<div style={{marginTop:14,padding:"12px 16px",background:"rgba(255,255,255,0.04)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:10,fontSize:13,color:"rgba(255,255,255,0.65)",lineHeight:1.6}}>💡 {data.exp||"Well answered!"}</div>}
    </div>
  );
}

function IdentifyChallenge({ data, onResult }) {
  const [sel,setSel]=useState(null);
  const [answered,setAnswered]=useState(false);
  const [imgFailed,setImgFailed]=useState(false);
  const submit=opt=>{if(answered)return;setSel(opt);setAnswered(true);setTimeout(()=>onResult(opt===data.answer),1500);};
  const showPhoto=data.img&&!imgFailed;
  return(
    <div>
      <div style={{textAlign:"center",marginBottom:16}}>
        {showPhoto?(
          <div style={{position:"relative",marginBottom:10,borderRadius:14,overflow:"hidden",height:160,background:"rgba(0,0,0,0.4)",border:"1px solid rgba(255,255,255,0.12)"}}>
            <img
              src={data.img}
              alt="organism"
              onError={()=>setImgFailed(true)}
              style={{width:"100%",height:"100%",objectFit:"cover",opacity:0.92,filter:"saturate(1.15) contrast(1.05)"}}
            />
            <div style={{position:"absolute",inset:0,background:"linear-gradient(to top,rgba(0,0,0,0.55) 0%,transparent 55%)"}}/>
            <div style={{position:"absolute",bottom:8,right:10,fontSize:22,filter:"drop-shadow(0 1px 4px rgba(0,0,0,0.8))"}}>{data.emoji}</div>
          </div>
        ):(
          <div style={{fontSize:52,marginBottom:8,animation:"float 2s ease-in-out infinite"}}>{data.emoji}</div>
        )}
        <div style={{background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:12,padding:"12px 16px",fontSize:14,color:"rgba(255,255,255,0.9)",lineHeight:1.6,fontStyle:"italic"}}>"{data.clue}"</div>
        <div style={{marginTop:8,fontSize:11,color:"rgba(255,255,255,0.4)",letterSpacing:"0.2em"}}>WHICH ORGANISM AM I?</div>
      </div>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10}}>
        {data.opts.map((opt,i)=>{
          let bg="rgba(255,255,255,0.07)",border="1px solid rgba(255,255,255,0.12)",color="rgba(255,255,255,0.85)";
          if(answered){if(opt===data.answer){bg="rgba(22,163,74,0.25)";border="1.5px solid #22c55e";color="#4ade80";}else if(opt===sel){bg="rgba(239,68,68,0.2)";border="1.5px solid #ef4444";color="#f87171";}}
          return <button key={i} onClick={()=>submit(opt)} style={{background:bg,border,borderRadius:12,padding:"13px 15px",color,fontFamily:"'Libre Baskerville',serif",fontSize:14,cursor:answered?"default":"pointer"}}>{opt}</button>;
        })}
      </div>
    </div>
  );
}

function HangmanChallenge({ data, onResult }) {
  const [guessed,setGuessed]=useState(new Set());
  const word=data.word.toUpperCase();
  const wrong=[...guessed].filter(l=>!word.includes(l));
  const solved=word.split("").every(l=>l===" "||guessed.has(l));
  const failed=wrong.length>=6;
  const done=useRef(false);
  useEffect(()=>{if((solved||failed)&&!done.current){done.current=true;setTimeout(()=>onResult(solved),800);}},[solved,failed]);
  const parts=["🗿","🎭","🦷","💀","👻","☠️"];
  return(
    <div>
      <p style={{textAlign:"center",fontSize:13,color:"rgba(255,255,255,0.55)",marginBottom:6,fontStyle:"italic"}}>Hint: {data.clue}</p>
      <div style={{textAlign:"center",fontSize:28,fontFamily:"'Cinzel',serif",marginBottom:14,letterSpacing:"0.2em"}}>
        {word.split("").map((l,i)=>(
          <span key={i} style={{display:"inline-block",minWidth:28,marginRight:4,borderBottom:l===" "?"none":"2px solid rgba(255,255,255,0.4)",color:guessed.has(l)?"#4ade80":"transparent"}}>{guessed.has(l)||l===" "?l:"_"}</span>
        ))}
      </div>
      <div style={{textAlign:"center",marginBottom:14}}>
        {parts.map((p,i)=><span key={i} style={{fontSize:20,opacity:i<wrong.length?1:0.1}}>{p}</span>)}
        <span style={{marginLeft:10,fontFamily:"'Cinzel',serif",fontSize:12,color:wrong.length>=4?"#f87171":"rgba(255,255,255,0.5)"}}>{wrong.length}/6</span>
      </div>
      <div style={{display:"flex",flexWrap:"wrap",gap:5,justifyContent:"center"}}>
        {"ABCDEFGHIJKLMNOPQRSTUVWXYZ".split("").map(l=>(
          <button key={l} disabled={guessed.has(l)||solved||failed} onClick={()=>setGuessed(prev=>new Set([...prev,l]))}
            style={{width:32,height:32,borderRadius:7,background:guessed.has(l)?(word.includes(l)?"rgba(22,163,74,0.3)":"rgba(239,68,68,0.2)"):"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.12)",color:guessed.has(l)?(word.includes(l)?"#4ade80":"#f87171"):"rgba(255,255,255,0.8)",fontFamily:"'Cinzel',serif",fontSize:11,fontWeight:700,cursor:guessed.has(l)||solved||failed?"default":"pointer"}}>
            {l}
          </button>
        ))}
      </div>
    </div>
  );
}

function MatchChallenge({ data, onResult }) {
  const terms=data.pairs.map(p=>p.term);
  const defs=useMemo(()=>shuffle(data.pairs.map(p=>p.def)),[]);
  const [selTerm,setSelTerm]=useState(null);
  const [matched,setMatched]=useState({});
  const [errors,setErrors]=useState(0);
  const done=useRef(false);
  const handleDef=def=>{
    if(!selTerm||done.current)return;
    const correct=data.pairs.find(p=>p.term===selTerm)?.def;
    if(def===correct){const newM={...matched,[selTerm]:def};setMatched(newM);setSelTerm(null);if(Object.keys(newM).length===data.pairs.length&&!done.current){done.current=true;setTimeout(()=>onResult(true),600);}}
    else{const e=errors+1;setErrors(e);setSelTerm(null);if(e>=3&&!done.current){done.current=true;setTimeout(()=>onResult(false),600);}}
  };
  return(
    <div>
      <p style={{textAlign:"center",fontSize:12,color:"rgba(255,255,255,0.5)",marginBottom:14}}>Click a TERM → then its DEFINITION · {errors}/3 errors</p>
      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:14}}>
        <div style={{display:"flex",flexDirection:"column",gap:7}}>
          <div style={{fontSize:10,letterSpacing:"0.2em",color:"rgba(255,255,255,0.35)",marginBottom:4,textAlign:"center"}}>CONCEPTS</div>
          {terms.map(t=>{const isM=matched[t];return(
            <button key={t} disabled={!!isM} onClick={()=>setSelTerm(selTerm===t?null:t)}
              style={{padding:"11px 13px",background:isM?"rgba(22,163,74,0.2)":selTerm===t?"rgba(124,58,237,0.3)":"rgba(255,255,255,0.06)",border:`1.5px solid ${isM?"#22c55e":selTerm===t?"#a78bfa":"rgba(255,255,255,0.1)"}`,borderRadius:10,color:isM?"#4ade80":selTerm===t?"#c4b5fd":"rgba(255,255,255,0.8)",fontFamily:"'Cinzel',serif",fontSize:11,cursor:isM?"default":"pointer",textAlign:"left"}}>
              {isM?"✓ ":""}{t}
            </button>
          );})}
        </div>
        <div style={{display:"flex",flexDirection:"column",gap:7}}>
          <div style={{fontSize:10,letterSpacing:"0.2em",color:"rgba(255,255,255,0.35)",marginBottom:4,textAlign:"center"}}>DEFINITIONS</div>
          {defs.map(d=>{const isM=Object.values(matched).includes(d);return(
            <button key={d} disabled={isM||!selTerm} onClick={()=>handleDef(d)}
              style={{padding:"11px 13px",background:isM?"rgba(22,163,74,0.15)":selTerm?"rgba(255,255,255,0.08)":"rgba(255,255,255,0.04)",border:"1.5px solid rgba(255,255,255,0.1)",borderRadius:10,color:isM?"rgba(74,222,128,0.7)":"rgba(255,255,255,0.75)",fontFamily:"'Libre Baskerville',serif",fontSize:11,cursor:isM||!selTerm?"default":"pointer",textAlign:"left"}}>
              {isM?"✓ ":""}{d}
            </button>
          );})}
        </div>
      </div>
    </div>
  );
}

function UnscrambleChallenge({ data, onResult }) {
  const [bank,setBank]=useState(()=>shuffle(data.words));
  const [answer,setAnswer]=useState([]);
  const [checked,setChecked]=useState(false);
  const [correct,setCorrect]=useState(false);
  const addWord=(w,i)=>{if(checked)return;setAnswer(p=>[...p,w]);setBank(p=>p.filter((_,idx)=>idx!==i));};
  const removeWord=i=>{if(checked)return;setBank(p=>[...p,answer[i]]);setAnswer(p=>p.filter((_,idx)=>idx!==i));};
  const check=()=>{const ok=answer.join(" ").toLowerCase()===data.ans.toLowerCase();setCorrect(ok);setChecked(true);setTimeout(()=>onResult(ok),1200);};
  return(
    <div>
      <p style={{textAlign:"center",fontSize:13,color:"rgba(255,255,255,0.5)",marginBottom:4,fontStyle:"italic"}}>Hint: {data.hint}</p>
      <p style={{textAlign:"center",fontSize:11,color:"rgba(255,255,255,0.3)",marginBottom:14}}>Click the words to build the sentence in order</p>
      <div style={{minHeight:50,background:"rgba(0,0,0,0.3)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:12,padding:"10px 14px",display:"flex",flexWrap:"wrap",gap:6,marginBottom:10,alignItems:"center"}}>
        {answer.length===0&&<span style={{color:"rgba(255,255,255,0.2)",fontSize:12}}>Your answer here…</span>}
        {answer.map((w,i)=><button key={i} onClick={()=>removeWord(i)} style={{background:"rgba(124,58,237,0.3)",border:"1px solid #a78bfa55",borderRadius:8,padding:"5px 10px",color:"#c4b5fd",fontFamily:"'Libre Baskerville',serif",fontSize:13,cursor:"pointer"}}>{w}</button>)}
      </div>
      <div style={{display:"flex",flexWrap:"wrap",gap:6,marginBottom:14}}>
        {bank.map((w,i)=><button key={i} onClick={()=>addWord(w,i)} style={{background:"rgba(255,255,255,0.08)",border:"1px solid rgba(255,255,255,0.15)",borderRadius:8,padding:"5px 11px",color:"rgba(255,255,255,0.85)",fontFamily:"'Libre Baskerville',serif",fontSize:13,cursor:"pointer"}}>{w}</button>)}
      </div>
      {!checked&&<button onClick={check} disabled={answer.length!==data.words.length} style={{width:"100%",padding:"12px",background:answer.length===data.words.length?"linear-gradient(135deg,#7c3aed,#6d28d9)":"rgba(255,255,255,0.05)",border:"none",borderRadius:10,color:answer.length===data.words.length?"#fff":"rgba(255,255,255,0.3)",fontFamily:"'Cinzel',serif",fontSize:13,fontWeight:700,cursor:answer.length===data.words.length?"pointer":"not-allowed",letterSpacing:"0.1em"}}>✓ Check Order</button>}
      {checked&&<div style={{textAlign:"center",fontSize:16,fontFamily:"'Cinzel',serif",color:correct?"#4ade80":"#f87171",animation:"popIn 0.4s ease"}}>{correct?"✓ Correct!":"✗ Incorrect"}</div>}
    </div>
  );
}

// ── CHALLENGE MODAL ────────────────────────────────
function ChallengeModal({ cell, ecosystem, team, pendingOrganism, onResult }) {
  const eco=ECOSYSTEMS[ecosystem.id];
  const ct=CT[cell.type];
  const [challenge]=useState(()=>{
    const c=eco.challenges;
    if(cell.type==="trivia")return pick(c.trivia);
    if(cell.type==="foodchain")return pick(c.foodchain);
    if(cell.type==="identify")return pick(c.identify);
    if(cell.type==="hangman")return pick(c.hangman);
    if(cell.type==="match")return pick(c.match);
    if(cell.type==="unscramble")return pick(c.unscramble);
    return null;
  });
  const [result,setResult]=useState(null);

  if(result!==null){
    const org=pendingOrganism;
    return(
      <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.85)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,padding:"1.5rem"}}>
        <div style={{background:"#0a0f1a",border:`2px solid ${result?"#22c55e":"#ef4444"}`,borderRadius:"1.3rem",padding:"2.2rem 2rem",maxWidth:"30rem",width:"100%",textAlign:"center",animation:"popIn 0.5s ease",boxShadow:`0 0 50px ${result?"rgba(34,197,94,0.3)":"rgba(239,68,68,0.3)"}`}}>
          <div style={{fontSize:"3.5rem",marginBottom:"0.5rem"}}>{result?"🎉":"😞"}</div>
          <h3 style={{fontFamily:"'Cinzel',serif",fontSize:"1.5rem",color:result?"#4ade80":"#f87171",marginBottom:"0.5rem"}}>{result?"Correct!":"No point this time"}</h3>
          {result&&org&&(
            <div style={{background:"rgba(34,197,94,0.1)",border:"1px solid #22c55e44",borderRadius:"0.9rem",padding:"1rem 1.2rem",margin:"1rem 0",animation:"popIn 0.5s ease 0.2s both"}}>
              <div style={{fontSize:"0.75rem",color:"#4ade80",letterSpacing:"0.2em",marginBottom:"0.4rem"}}>✨ ORGANISMO DESBLOQUEADO</div>
              <div style={{fontSize:"2.8rem",marginBottom:"0.3rem"}}>{org.emoji}</div>
              <div style={{fontFamily:"'Cinzel',serif",fontSize:"1rem",color:"#fff",fontWeight:700}}>{org.name}</div>
              <div style={{fontSize:"0.75rem",color:"rgba(255,255,255,0.5)",marginTop:"0.3rem"}}>{org.role}</div>
            </div>
          )}
          {result&&!org&&<p style={{color:"rgba(255,255,255,0.5)",fontSize:"0.9rem"}}>You already have all organisms</p>}
          {!result&&<p style={{color:"rgba(255,255,255,0.5)",fontSize:"0.9rem"}}>Turn passes to the next team</p>}
          <button onClick={()=>onResult(result,result?org:null)} style={{marginTop:"1.2rem",padding:"0.85rem 2.4rem",background:result?"linear-gradient(135deg,#16a34a,#15803d)":"rgba(255,255,255,0.08)",border:"none",borderRadius:"0.8rem",color:"#fff",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:"0.9rem",cursor:"pointer",letterSpacing:"0.1em"}}>Continue →</button>
        </div>
      </div>
    );
  }
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.8)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200,padding:"1.5rem"}}>
      <div style={{background:"#0a0f1a",border:`2px solid ${ct.color}55`,borderRadius:"1.3rem",padding:"1.8rem",maxWidth:"42rem",width:"100%",boxShadow:`0 0 50px ${ct.color}22`,maxHeight:"90vh",overflowY:"auto"}}>
        <div style={{display:"flex",alignItems:"center",gap:"0.9rem",marginBottom:"1.2rem"}}>
          <div style={{width:"3rem",height:"3rem",borderRadius:"0.8rem",background:ct.bg,border:`2px solid ${ct.color}44`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"1.4rem"}}>{ct.icon}</div>
          <div>
            <div style={{fontFamily:"'Cinzel',serif",fontSize:"1rem",color:ct.color,letterSpacing:"0.1em",fontWeight:700}}>{ct.label}</div>
            <div style={{fontSize:"0.8rem",color:TEAM_COLORS[team.colorIdx].light}}>● {team.name}</div>
          </div>
          {pendingOrganism&&<div style={{marginLeft:"auto",background:"rgba(34,197,94,0.1)",border:"1px solid rgba(34,197,94,0.3)",borderRadius:"0.65rem",padding:"0.35rem 0.75rem",fontSize:"0.78rem",color:"#4ade80"}}>Prize: {pendingOrganism.emoji} {pendingOrganism.name}</div>}
        </div>
        {cell.type==="trivia"&&<TriviaChallenge data={challenge} onResult={setResult} />}
        {cell.type==="foodchain"&&<TriviaChallenge data={{...challenge,exp:"That's how energy flows in this food chain!"}} onResult={setResult} />}
        {cell.type==="identify"&&<IdentifyChallenge data={challenge} onResult={setResult} />}
        {cell.type==="hangman"&&<HangmanChallenge data={challenge} onResult={setResult} />}
        {cell.type==="match"&&<MatchChallenge data={challenge} onResult={setResult} />}
        {cell.type==="unscramble"&&<UnscrambleChallenge data={challenge} onResult={setResult} />}
      </div>
    </div>
  );
}

// ── WILDCARD MODAL ─────────────────────────────────
function WildcardModal({ cell, onDone }) {
  const effects={advance:{icon:"⏩",title:"Move Forward!",desc:`Move forward ${cell.val} extra spaces`,color:"#4ade80"},back:{icon:"⏪",title:"Move Back!",desc:`Go back ${cell.val} spaces`,color:"#f87171"},skip:{icon:"⏭️",title:"Lose a Turn!",desc:"You skip your next turn",color:"#fbbf24"},free:{icon:"🎁",title:"Free Organism!",desc:"You get an organism without a challenge!",color:"#c084fc"},steal:{icon:"🦅",title:"Steal an Organism!",desc:"Take an organism from the team with the most",color:"#fb923c"},double:{icon:"✨",title:"Double Reward!",desc:"Your next correct answer counts as 2",color:"#38bdf8"}};
  const fx=effects[cell.fx]||{icon:"⚡",title:"Wildcard",desc:"Special effect",color:"#e879f9"};
  return(
    <div style={{position:"fixed",inset:0,background:"rgba(0,0,0,0.82)",display:"flex",alignItems:"center",justifyContent:"center",zIndex:200}}>
      <div style={{background:"#0a0f1a",border:`2px solid ${fx.color}55`,borderRadius:"1.3rem",padding:"2.6rem 2.2rem",maxWidth:"28rem",textAlign:"center",animation:"popIn 0.5s ease",boxShadow:`0 0 60px ${fx.color}33`}}>
        <div style={{fontSize:"4rem",marginBottom:"0.5rem"}}>{fx.icon}</div>
        <h3 style={{fontFamily:"'Cinzel',serif",fontSize:"1.5rem",color:fx.color,marginBottom:"0.65rem"}}>{fx.title}</h3>
        <p style={{color:"rgba(255,255,255,0.65)",fontSize:"0.95rem",lineHeight:1.5}}>{fx.desc}</p>
        <button onClick={onDone} style={{marginTop:"1.4rem",padding:"0.85rem 2.2rem",background:`${fx.color}33`,border:`1.5px solid ${fx.color}55`,borderRadius:"0.8rem",color:"#fff",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:"0.9rem",cursor:"pointer",letterSpacing:"0.1em"}}>Continue →</button>
      </div>
    </div>
  );
}

// ── TEAM PANEL ─────────────────────────────────────
function TeamPanel({ teams, currentTeamIdx, ecosystem }) {
  const eco=ECOSYSTEMS[ecosystem.id];
  return(
    <div style={{display:"flex",flexDirection:"column",gap:"0.7rem",overflowY:"auto",maxHeight:"100%"}}>
      {teams.map((team,i)=>{
        const isA=i===currentTeamIdx,tc=TEAM_COLORS[team.colorIdx],col=team.organisms||[],total=eco.organisms.length,pct=Math.round((col.length/total)*100);
        return(
          <div key={team.id} style={{background:isA?`${tc.bg}15`:"rgba(255,255,255,0.03)",border:`1.5px solid ${isA?tc.bg:"rgba(255,255,255,0.07)"}`,borderRadius:"0.9rem",padding:"0.85rem 0.9rem",transition:"all 0.3s",boxShadow:isA?`0 0 14px ${tc.bg}33`:"none"}}>
            <div style={{display:"flex",alignItems:"center",gap:"0.55rem",marginBottom:"0.5rem"}}>
              <div style={{width:"0.65rem",height:"0.65rem",borderRadius:"50%",background:tc.bg,boxShadow:`0 0 6px ${tc.bg}`}} />
              <span style={{fontFamily:"'Cinzel',serif",fontSize:"0.8rem",color:isA?tc.light:"rgba(255,255,255,0.7)",fontWeight:isA?700:400}}>{team.name}</span>
              {isA&&<span style={{marginLeft:"auto",fontSize:"0.6rem",background:tc.bg,color:"#fff",borderRadius:"0.5rem",padding:"0.15rem 0.5rem",letterSpacing:"0.1em",fontFamily:"'Cinzel',serif"}}>TURN</span>}
              {team.skipNext&&<span style={{marginLeft:"auto",fontSize:"0.6rem",background:"#7f1d1d",color:"#fca5a5",borderRadius:"0.5rem",padding:"0.15rem 0.5rem"}}>SKIP</span>}
              {team.doubleNext&&<span style={{marginLeft:"auto",fontSize:"0.6rem",background:"#1e3a8a",color:"#93c5fd",borderRadius:"0.5rem",padding:"0.15rem 0.5rem"}}>×2</span>}
            </div>
            <div style={{fontSize:"0.65rem",color:"rgba(255,255,255,0.35)",marginBottom:"0.4rem"}}>Square {team.position+1} of {eco.boardSize||81} · {col.length}/{total} organisms</div>
            <div style={{height:"0.3rem",background:"rgba(255,255,255,0.06)",borderRadius:"0.2rem",marginBottom:"0.5rem",overflow:"hidden"}}>
              <div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${tc.bg},${tc.light})`,borderRadius:"0.2rem",transition:"width 0.5s ease"}} />
            </div>
            <div style={{display:"flex",flexWrap:"wrap",gap:"0.2rem"}}>
              {eco.organisms.map(org=>{
                const has=col.find(c=>c.id===org.id);
                return(<div key={org.id} title={org.name} style={{width:"1.7rem",height:"1.7rem",borderRadius:"0.4rem",background:has?"rgba(255,255,255,0.1)":"rgba(255,255,255,0.03)",border:`1px solid ${has?tc.bg+"55":"rgba(255,255,255,0.06)"}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:"0.95rem",opacity:has?1:0.2,transition:"all 0.3s",animation:has?"popIn 0.4s ease":undefined}}>{org.emoji}</div>);
              })}
            </div>
          </div>
        );
      })}
    </div>
  );
}

// ── DICE ───────────────────────────────────────────
function Dice({ value, rolling }) {
  const faces=["⚀","⚁","⚂","⚃","⚄","⚅"];
  return(<div style={{width:"4.8rem",height:"4.8rem",borderRadius:"0.9rem",background:"rgba(255,255,255,0.08)",border:"2px solid rgba(255,255,255,0.2)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:"3rem",boxShadow:"0 4px 24px rgba(0,0,0,0.4)",animation:rolling?"diceRoll 0.15s ease-in-out infinite":undefined,flexShrink:0}}>
    {value?faces[value-1]:"🎲"}
  </div>);
}

// ── GAME SCREEN ─────────────────────────────────────
function GameScreen({ ecosystem, initTeams, firstTeamIdx, onEnd }) {
  const eco=ECOSYSTEMS[ecosystem.id];
  const N_BOARD = eco.boardSize;
  const board = useMemo(() => generateBoard(N_BOARD), [N_BOARD]);
  const [teams,setTeams]=useState(()=>initTeams.map(t=>({...t,position:0,organisms:[],skipNext:false,doubleNext:false})));
  const [curIdx,setCurIdx]=useState(firstTeamIdx);
  const [phase,setPhase]=useState("idle");
  const [diceVal,setDiceVal]=useState(null);
  const [rolling,setRolling]=useState(false);
  const [activeCell,setActiveCell]=useState(null);
  const [pendingOrg,setPendingOrg]=useState(null);
  const [turn,setTurn]=useState(1);
  const [narrativePopup, setNarrativePopup] = useState(null);
  const [revealedChapters, setRevealedChapters] = useState(new Set([0]));
  const [correctAnswers, setCorrectAnswers] = useState(0);
  const curTeam=teams[curIdx];
  const tc=TEAM_COLORS[curTeam?.colorIdx||0];

  const getUncollected=team=>{const ids=team.organisms.map(o=>o.id);return eco.organisms.filter(o=>!ids.includes(o.id));};

  const rollDice=()=>{
    if(phase!=="idle")return;
    setRolling(true);setPhase("rolling");
    let ticks=0;
    const iv=setInterval(()=>{
      setDiceVal(Math.floor(Math.random()*6)+1);ticks++;
      if(ticks>10){clearInterval(iv);const v=Math.floor(Math.random()*6)+1;setDiceVal(v);setRolling(false);setTimeout(()=>moveTeam(v),300);}
    },100);
  };

  const moveTeam=steps=>{
    const team=teams[curIdx];
    const newPos=Math.min(team.position+steps,N_BOARD-1);
    setTeams(prev=>{const u=[...prev];u[curIdx]={...u[curIdx],position:newPos};return u;});
    // Chapter narrative
    const chapterIdx=Math.floor(newPos/6);
    if(!revealedChapters.has(chapterIdx)){
      const chapter=eco.chapters?.[chapterIdx];
      if(chapter){
        setRevealedChapters(prev=>new Set([...prev,chapterIdx]));
        setNarrativePopup(chapter);
        setTimeout(()=>setNarrativePopup(null),4500);
      }
    }
    const cell=board[newPos];
    setTimeout(()=>{
      if(cell.type==="center"){setPhase("center");}
      else if(cell.type==="wildcard"){setActiveCell(cell);setPhase("wildcard");}
      else if(cell.type==="start"){nextTurn();}
      else{const uncol=getUncollected(teams[curIdx]);setPendingOrg(uncol.length>0?pick(uncol):null);setActiveCell(cell);setPhase("challenge");}
    },500);
  };

  const handleWildcardDone=()=>{
    const cell=activeCell;if(!cell){nextTurn();return;}
    if(cell.fx==="advance")setTeams(p=>{const u=[...p];u[curIdx]={...u[curIdx],position:Math.min(u[curIdx].position+cell.val,N_BOARD-1)};return u;});
    else if(cell.fx==="back")setTeams(p=>{const u=[...p];u[curIdx]={...u[curIdx],position:Math.max(0,u[curIdx].position-cell.val)};return u;});
    else if(cell.fx==="skip"){const skipTarget=(curIdx+1)%teams.length;setActiveCell(null);nextTurn(skipTarget);return;}
    else if(cell.fx==="free"){const uncol=getUncollected(teams[curIdx]);if(uncol.length>0){const org=pick(uncol);setTeams(p=>{const u=[...p];u[curIdx]={...u[curIdx],organisms:[...u[curIdx].organisms,org]};return u;});}}
    else if(cell.fx==="steal"){const rich=[...teams].filter((_,i)=>i!==curIdx).sort((a,b)=>b.organisms.length-a.organisms.length)[0];if(rich&&rich.organisms.length>0){const st=rich.organisms[rich.organisms.length-1];setTeams(p=>{const u=[...p];u[curIdx]={...u[curIdx],organisms:[...u[curIdx].organisms,st]};u[rich.id]={...u[rich.id],organisms:u[rich.id].organisms.filter(o=>o.id!==st.id)};return u;});}}
    else if(cell.fx==="double")setTeams(p=>{const u=[...p];u[curIdx]={...u[curIdx],doubleNext:true};return u;});
    setActiveCell(null);nextTurn();
  };

  const handleChallengeResult=(won,org)=>{
    if(won&&org){
      setCorrectAnswers(c=>c+1);
      const isDouble=teams[curIdx].doubleNext;
      setTeams(p=>{const u=[...p];const newOrgs=[...u[curIdx].organisms];if(!newOrgs.find(o=>o.id===org.id))newOrgs.push(org);if(isDouble){const u2=eco.organisms.filter(o=>!newOrgs.find(n=>n.id===o.id));if(u2.length>0)newOrgs.push(pick(u2));}u[curIdx]={...u[curIdx],organisms:newOrgs,doubleNext:false};return u;});
    }
    setPendingOrg(null);setActiveCell(null);nextTurn();
  };

  const nextTurn=(skipIdx=null)=>{
    setPhase("idle");setDiceVal(null);setTurn(t=>t+1);
    let next=(curIdx+1)%teams.length;
    // skipIdx: index of the team that should be skipped this round
    if(skipIdx!==null&&next===skipIdx){next=(next+1)%teams.length;}
    else if(skipIdx===null&&teams[next]?.skipNext){setTeams(p=>{const u=[...p];u[next]={...u[next],skipNext:false};return u;});next=(next+1)%teams.length;}
    setCurIdx(next);
  };

  if(phase==="center")return <VictoryScreen teams={teams} ecosystem={ecosystem} winner={teams[curIdx]} onRestart={onEnd} />;

  // Revealed ecosystem elements (unique per chapter)
  const revealedElements = [...revealedChapters]
    .sort((a,b)=>a-b)
    .map(i=>eco.chapters?.[i])
    .filter(Boolean)
    .filter(c=>c.element!=="🌑");

  return(
    <div style={{height:"100vh",background:eco.bg,fontFamily:"'Libre Baskerville',serif",display:"flex",flexDirection:"column",overflow:"hidden"}}>
      {/* Top bar */}
      <div style={{background:"rgba(0,0,0,0.5)",backdropFilter:"blur(12px)",borderBottom:"1px solid rgba(255,255,255,0.06)",padding:"0.7rem 1.4rem",display:"flex",alignItems:"center",gap:"1rem",flexShrink:0}}>
        <span style={{fontSize:"1.6rem"}}>{eco.emoji}</span>
        <div>
          <div style={{fontFamily:"'Cinzel',serif",fontSize:"1rem",color:"#fff",fontWeight:700}}>{eco.name}</div>
          <div style={{fontSize:"0.65rem",color:"rgba(255,255,255,0.4)",letterSpacing:"0.1em"}}>Turn {turn} · Square {curTeam?.position+1}/{N_BOARD}</div>
        </div>
        {/* Revealed elements strip */}
        <div style={{display:"flex",gap:"0.35rem",marginLeft:"0.9rem",flexWrap:"wrap",maxWidth:"16rem"}}>
          {revealedElements.map((ch,i)=>(
            <span key={i} title={ch.title} style={{fontSize:"1.2rem",animation:"popIn 0.4s ease",filter:`drop-shadow(0 0 6px ${eco.glow})`}}>{ch.element}</span>
          ))}
        </div>
        <div style={{marginLeft:"auto",display:"flex",gap:"0.6rem",alignItems:"center"}}>
          <div style={{width:"0.7rem",height:"0.7rem",borderRadius:"50%",background:tc.bg,boxShadow:`0 0 8px ${tc.bg}`}} />
          <span style={{fontFamily:"'Cinzel',serif",fontSize:"0.9rem",color:tc.light}}>{curTeam?.name}</span>
          <span style={{fontSize:"0.75rem",color:"rgba(255,255,255,0.35)"}}>playing</span>
        </div>
        <button onClick={onEnd} style={{padding:"0.35rem 0.9rem",background:"rgba(255,255,255,0.06)",border:"1px solid rgba(255,255,255,0.1)",borderRadius:"0.5rem",color:"rgba(255,255,255,0.5)",fontFamily:"'Cinzel',serif",fontSize:"0.75rem",cursor:"pointer"}}>Exit</button>
      </div>

      {/* Chapter narrative popup */}
      {narrativePopup&&(
        <div style={{position:"fixed",top:72,left:"50%",transform:"translateX(-50%)",zIndex:150,maxWidth:540,width:"92%",background:"rgba(0,0,0,0.92)",border:`1px solid ${eco.glow}55`,borderRadius:18,overflow:"hidden",boxShadow:`0 0 40px ${eco.glow}44`,animation:"narrativeSlide 0.5s ease",backdropFilter:"blur(14px)"}}>
          {narrativePopup.img&&(
            <div style={{position:"relative",height:120,overflow:"hidden"}}>
              <img
                src={narrativePopup.img}
                alt={narrativePopup.title}
                onError={e=>{e.target.style.display="none";}}
                style={{width:"100%",height:"100%",objectFit:"cover",filter:`saturate(1.2) brightness(0.75) hue-rotate(${eco.glow==="transparent"?0:0}deg)`}}
              />
              <div style={{position:"absolute",inset:0,background:`linear-gradient(to bottom, transparent 30%, rgba(0,0,0,0.85) 100%)`}}/>
              <div style={{position:"absolute",bottom:10,left:16,fontFamily:"'Cinzel',serif",fontSize:13,color:eco.color,letterSpacing:"0.15em",fontWeight:700,textShadow:"0 1px 6px rgba(0,0,0,0.9)"}}>{narrativePopup.title}</div>
              <div style={{position:"absolute",top:8,right:10,fontSize:24,filter:`drop-shadow(0 0 8px ${eco.glow})`}}>{narrativePopup.element}</div>
            </div>
          )}
          <div style={{padding:"14px 20px",display:"flex",alignItems:"flex-start",gap:12}}>
            {!narrativePopup.img&&<span style={{fontSize:28,filter:`drop-shadow(0 0 8px ${eco.glow})`,flexShrink:0,marginTop:2}}>{narrativePopup.element}</span>}
            <div>
              {!narrativePopup.img&&<div style={{fontFamily:"'Cinzel',serif",fontSize:11,color:eco.color,letterSpacing:"0.2em",marginBottom:5}}>{narrativePopup.title}</div>}
              <div style={{fontSize:13,color:"rgba(255,245,210,0.9)",lineHeight:1.6,fontStyle:"italic"}}>{narrativePopup.narrative}</div>
            </div>
          </div>
        </div>
      )}

      {/* Main layout */}
      <div style={{flex:1,display:"flex",overflow:"hidden"}}>
        {/* Board area */}
        <div style={{flex:1,position:"relative",overflow:"hidden"}}>

          {/* ── ECOSYSTEM BACKGROUND: organisms appear as they're collected ── */}
          <div style={{position:"absolute",inset:0,zIndex:0,overflow:"hidden"}}>
            {/* Ecosystem background image or gradient fallback */}
            {ECO_IMAGES[eco.id] ? (
              <img
                src={ECO_IMAGES[eco.id]}
                alt=""
                style={{
                  position:"absolute",inset:0,width:"100%",height:"100%",
                  objectFit:"cover",
                  filter:"brightness(0.82) saturate(1.1)",
                }}
              />
            ) : (
              <div style={{position:"absolute",inset:0,background:eco.bg}} />
            )}
            {eco.organisms.map((org, i) => {
              // Spread across full board, corners and edges included
              const positions = [
                {left:"5%",  top:"12%", size:90},  {left:"78%", top:"6%",  size:80},
                {left:"50%", top:"76%", size:100}, {left:"18%", top:"58%", size:85},
                {left:"68%", top:"42%", size:95},  {left:"35%", top:"14%", size:75},
                {left:"12%", top:"80%", size:88},  {left:"85%", top:"62%", size:82},
                {left:"42%", top:"46%", size:70},  {left:"60%", top:"22%", size:92},
                {left:"25%", top:"35%", size:78},  {left:"72%", top:"82%", size:96},
              ];
              const pos = positions[i % positions.length];
              const collected = teams.some(t => t.organisms.find(o => o.id === org.id));
              return (
                <div key={org.id} style={{
                  position:"absolute",
                  left: pos.left, top: pos.top,
                  fontSize: pos.size,
                  opacity: collected ? 0.38 : 0,
                  transform: collected ? "scale(1) rotate(0deg)" : "scale(0.1) rotate(-20deg)",
                  transition: "opacity 2s ease, transform 2s cubic-bezier(0.34,1.56,0.64,1)",
                  filter: collected
                    ? `drop-shadow(0 0 28px ${eco.glow}) drop-shadow(0 0 8px ${eco.color}88)`
                    : "none",
                  pointerEvents:"none",
                  animation: collected ? `float ${5 + (i%3)}s ease-in-out infinite` : "none",
                  animationDelay: `${i * 0.6}s`,
                  userSelect:"none",
                  lineHeight:1,
                }}>
                  {org.emoji}
                </div>
              );
            })}
            {/* Dark center vignette so board tiles in center read clearly */}
            <div style={{position:"absolute",inset:0,background:"radial-gradient(ellipse at 50% 45%, rgba(0,0,0,0.55) 25%, rgba(0,0,0,0.1) 75%)",pointerEvents:"none"}} />
          </div>

          <div style={{position:"absolute",inset:0,zIndex:1}}>
            <IsometricBoard teams={teams} currentTeamIdx={curIdx} board={board} gridSize={eco.gridSize} hasImage={!!ECO_IMAGES[eco.id]} />
          </div>
          {/* Dice controls overlay */}
          <div style={{position:"absolute",bottom:"1rem",left:"50%",transform:"translateX(-50%)",zIndex:10,display:"flex",alignItems:"center",gap:"1.2rem",background:"rgba(0,0,0,0.75)",backdropFilter:"blur(14px)",border:"1px solid rgba(255,255,255,0.12)",borderRadius:"1.1rem",padding:"0.9rem 1.5rem",boxShadow:"0 8px 40px rgba(0,0,0,0.6)"}}>
            <Dice value={diceVal} rolling={rolling} />
            <div>
              <div style={{fontFamily:"'Cinzel',serif",fontSize:"0.85rem",color:tc.light,marginBottom:"0.2rem"}}>Turn: {curTeam?.name}</div>
              <div style={{fontSize:"0.75rem",color:"rgba(255,255,255,0.4)",marginBottom:"0.5rem"}}>{curTeam?.players?.join(" · ")}</div>
              <button onClick={rollDice} disabled={phase!=="idle"} style={{padding:"0.6rem 1.6rem",background:phase==="idle"?`linear-gradient(135deg,${tc.bg},${tc.dark})`:"rgba(255,255,255,0.05)",border:"none",borderRadius:"0.7rem",color:phase==="idle"?"#fff":"rgba(255,255,255,0.3)",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:"0.9rem",cursor:phase==="idle"?"pointer":"not-allowed",letterSpacing:"0.1em",boxShadow:phase==="idle"?`0 4px 20px ${tc.bg}55`:"none"}}>
                {phase==="idle"?"🎲 Roll Dice":phase==="rolling"?"Rolling…":"Wait…"}
              </button>
            </div>
            {diceVal&&<div style={{textAlign:"center",minWidth:"3rem"}}>
              <div style={{fontSize:"0.65rem",color:"rgba(255,255,255,0.4)",marginBottom:"0.1rem"}}>Result</div>
              <div style={{fontFamily:"'Cinzel',serif",fontSize:"1.8rem",color:"#fde047",fontWeight:700}}>{diceVal}</div>
            </div>}
          </div>
        </div>

        {/* Right sidebar */}
        <div style={{width:"18rem",background:"rgba(0,0,0,0.45)",borderLeft:"1px solid rgba(255,255,255,0.07)",padding:"1rem 0.9rem",overflowY:"auto",flexShrink:0}}>
          <div style={{fontSize:"0.65rem",letterSpacing:"0.25em",color:"rgba(255,255,255,0.35)",marginBottom:"0.7rem"}}>TEAMS · ECOSYSTEM</div>
          <TeamPanel teams={teams} currentTeamIdx={curIdx} ecosystem={ecosystem} />
        </div>
      </div>

      {phase==="challenge"&&activeCell&&<ChallengeModal cell={activeCell} ecosystem={ecosystem} team={curTeam} pendingOrganism={pendingOrg} onResult={handleChallengeResult} />}
      {phase==="wildcard"&&activeCell&&<WildcardModal cell={activeCell} onDone={handleWildcardDone} />}
    </div>
  );
}

// ── VICTORY ─────────────────────────────────────────
function VictoryScreen({ teams, ecosystem, winner, onRestart }) {
  const eco=ECOSYSTEMS[ecosystem.id];
  const sorted=[...teams].sort((a,b)=>b.organisms.length-a.organisms.length);
  const confetti = useMemo(() => Array.from({length:30}, () => ({
    left: Math.random()*100, top: Math.random()*100,
    size: Math.random()*20+10, delay: Math.random()*4, dur: 2+Math.random()*3
  })), []);
  return(
    <div style={{minHeight:"100vh",background:eco.bg,display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",fontFamily:"'Libre Baskerville',serif",padding:24,position:"relative",overflow:"hidden"}}>
      {confetti.map((p,i)=>(
        <div key={i} style={{position:"absolute",left:`${p.left}%`,top:`${p.top}%`,fontSize:p.size,opacity:0.2,animation:`float ${p.dur}s ease-in-out ${p.delay}s infinite`,pointerEvents:"none"}}>{["🎉","⭐","🌟","✨","🏆"][i%5]}</div>
      ))}
      <div style={{fontSize:10,letterSpacing:"0.4em",color:eco.color,marginBottom:10}}>JUEGO TERMINADO</div>
      <h1 style={{fontFamily:"'Cinzel Decorative',serif",fontSize:28,color:"#fff",textShadow:`0 0 40px ${eco.color}66`,marginBottom:8,textAlign:"center"}}>{sorted[0].name} Wins!</h1>
      <div style={{fontSize:40,marginBottom:8,animation:"float 2s ease-in-out infinite"}}>{eco.emoji}</div>
      <p style={{color:"rgba(255,255,255,0.5)",fontSize:13,marginBottom:30}}>{winner?.name} reached the center of the board</p>
      <div style={{width:"100%",maxWidth:580,display:"flex",flexDirection:"column",gap:10,marginBottom:30}}>
        {sorted.map((team,i)=>{
          const tc=TEAM_COLORS[team.colorIdx],pct=Math.round((team.organisms.length/eco.organisms.length)*100);
          return(
            <div key={team.id} style={{background:i===0?"rgba(255,255,255,0.08)":"rgba(255,255,255,0.04)",border:`2px solid ${i===0?tc.bg:"rgba(255,255,255,0.08)"}`,borderRadius:14,padding:"13px 16px",display:"flex",alignItems:"center",gap:12,boxShadow:i===0?`0 0 20px ${tc.bg}44`:"none"}}>
              <div style={{width:34,height:34,borderRadius:"50%",background:i===0?"#fde047":i===1?"#e5e7eb":i===2?"#cd7c32":"rgba(255,255,255,0.1)",display:"flex",alignItems:"center",justifyContent:"center",fontFamily:"'Cinzel',serif",fontSize:16,fontWeight:700,color:"#000",flexShrink:0}}>
                {i===0?"🥇":i===1?"🥈":i===2?"🥉":`${i+1}`}
              </div>
              <div style={{flex:1}}>
                <div style={{display:"flex",alignItems:"center",gap:8,marginBottom:5}}>
                  <div style={{width:9,height:9,borderRadius:"50%",background:tc.bg}} />
                  <span style={{fontFamily:"'Cinzel',serif",fontSize:13,color:"#fff",fontWeight:700}}>{team.name}</span>
                  <span style={{fontSize:10,color:"rgba(255,255,255,0.4)"}}>{team.players?.join(", ")}</span>
                </div>
                <div style={{height:5,background:"rgba(255,255,255,0.08)",borderRadius:3,overflow:"hidden",marginBottom:5}}>
                  <div style={{height:"100%",width:`${pct}%`,background:`linear-gradient(90deg,${tc.bg},${tc.light})`,borderRadius:3}} />
                </div>
                <div style={{display:"flex",flexWrap:"wrap",gap:4,alignItems:"center"}}>
                  {team.organisms.map(org=><span key={org.id} style={{fontSize:16}}>{org.emoji}</span>)}
                  <span style={{fontSize:10,color:"rgba(255,255,255,0.4)",marginLeft:4}}>{team.organisms.length}/{eco.organisms.length}</span>
                </div>
              </div>
            </div>
          );
        })}
      </div>
      <button onClick={onRestart} style={{padding:"14px 42px",background:"linear-gradient(135deg,#16a34a,#15803d)",border:"none",borderRadius:14,color:"#fff",fontFamily:"'Cinzel',serif",fontWeight:700,fontSize:14,cursor:"pointer",letterSpacing:"0.1em",boxShadow:"0 8px 30px rgba(22,163,74,0.5)"}}>🌍 Play Again</button>
    </div>
  );
}

// ── ROOT ───────────────────────────────────────────
export default function App() {
  const [screen,setScreen]=useState("setup");
  const [ecosystem,setEcosystem]=useState(null);
  const [gameTeams,setGameTeams]=useState([]);
  const [firstTeam,setFirstTeam]=useState(0);
  const handleSetupDone=(eco,teams)=>{setEcosystem(eco);setGameTeams(teams);setScreen("genesis");};
  const handleGenesisDone=idx=>{setFirstTeam(idx);setScreen("game");};
  return(
    <>
      <style>{GS}</style>
      {screen==="setup"&&<SetupScreen onStart={handleSetupDone} />}
      {screen==="genesis"&&gameTeams.length>0&&<GenesisScreen teams={gameTeams} ecosystem={ecosystem} onStart={handleGenesisDone} />}
      {screen==="game"&&ecosystem&&<GameScreen ecosystem={ecosystem} initTeams={gameTeams} firstTeamIdx={firstTeam} onEnd={()=>setScreen("setup")} />}
    </>
  );
}
